class Node {
  constructor(value) {
    this.value = value;
    this.next = null;
  }
}

// Build: 10 → 20 → 30 → null
const head = new Node(10);
head.next = new Node(20);
head.next.next = new Node(30);

// Walk the list
let cur = head;
while (cur) {
  console.log(cur.value);
  cur = cur.next;
}
